// ============================================
// WF-05 — BATCHES 10 leads + HMAC
// Prompt rescore_v1 — L1 Llama, temp 0.1
// Champs réels Odoo : x_ai_score, x_ai_processed_date, x_ismail_source
// ============================================
const crypto = require('crypto');
const leads = $input.all().map(item => item.json);
const batchSize = 10;
const batches = [];

for (let i = 0; i < leads.length; i += batchSize) {
  const batch = leads.slice(i, i + batchSize);
  const batchId = `rescore_${new Date().toISOString().split('T')[0]}_batch_${Math.floor(i/batchSize)+1}`;

  const ismailPayload = {
    batch_id: batchId,
    rescore_reason: 'cron_quotidien_02h00',
    leads: batch.map(l => ({
      lead_id: l.id,
      x_score_actuel: l.x_ai_score || 0,
      last_interaction: l.x_ai_processed_date || l.write_date || l.create_date,
      stage_name: l.stage_id?.[1] || 'Nouveau',
      x_secteur: l.x_secteur || 'Consulting',
      x_pays: l.x_pays || 'MA',
      recent_activities: []
    })),
    metadata: {
      timestamp: Math.floor(Date.now() / 1000),
      source: 'n8n_cron',
      total_leads: leads.length,
      batch_number: Math.floor(i/batchSize)+1,
      total_batches: Math.ceil(leads.length/batchSize),
      prompt_version: 'rescore_v1',
      llm_level: 'L1_Llama',
      temperature: 0.1
    }
  };

  const secret = $credentials.ismail_webhook_secret.secret;
  const body = JSON.stringify(ismailPayload);
  const signature = 'sha256=' + crypto.createHmac('sha256', secret).update(body).digest('hex');

  batches.push({ json: {
    payload: ismailPayload,
    hmac_signature: signature,
    workflow_name: $workflow.name,
    execution_id: $execution.id,
    batch_index: Math.floor(i/batchSize)+1,
    total_batches: Math.ceil(leads.length/batchSize)
  }});
}

return batches;

// Agrégation résultats + calcul rapport hebdo lundi
const all = $input.all();
let total_rescored = 0, total_moved = 0, total_archived = 0, errors = [];

for (const item of all) {
  const result = item.json;
  if (result.success && result.result) {
    total_rescored += result.result.rescored_count || 0;
    total_moved += result.result.moved_count || 0;
    total_archived += result.result.archived_count || 0;
  } else if (!result.success) {
    errors.push(result.error || 'Erreur inconnue');
  }
}

// Rapport hebdo uniquement le lundi
const isLundi = new Date().getDay() === 1;

return [{ json: {
  rapport: {
    date: new Date().toISOString().split('T')[0],
    jour: new Date().toLocaleDateString('fr-FR', { weekday: 'long' }),
    total_leads_traites: total_rescored,
    leads_moves_stage: total_moved,
    leads_archives: total_archived,
    erreurs: errors.length,
    details_erreurs: errors,
    is_lundi: isLundi
  }
}}];
